// ── Build LaTeX Resume ─────────────────────────────────────────────────────
const raw = ($('Merge Job Data').item.json.output ?? '').trim();

function esc(s) {
  return String(s ?? '')
    .replace(/\\/g,  '\\textbackslash{}')
    .replace(/&/g,   '\\&')
    .replace(/%/g,   '\\%')
    .replace(/\$/g,  '\\$')
    .replace(/#/g,   '\\#')
    .replace(/_/g,   '\\_')
    .replace(/\{/g,  '\\{')
    .replace(/\}/g,  '\\}')
    .replace(/~/g,   '\\textasciitilde{}')
    .replace(/\^/g,  '\\textasciicircum{}');
}

function section(text, header) {
  const re = new RegExp(
    '(?:^|\\n)' + header.replace(/ /g, '\\s+') + '\\s*\\n([\\s\\S]*?)(?=\\n[A-Z][A-Z ]{2,}\\s*\\n|$)',
    'i'
  );
  const m = text.match(re);
  return m ? m[1].trim() : '';
}

const nameRaw       = section(raw, 'NAME');
const contactRaw    = section(raw, 'CONTACT');
const summaryRaw    = section(raw, 'SUMMARY');
const experienceRaw = section(raw, 'PROFESSIONAL EXPERIENCE');
const educationRaw  = section(raw, 'EDUCATION');
const skillsRaw     = section(raw, 'SKILLS');

const fullName  = (nameRaw.split('\n')[0] || 'Your Name').trim();
const parts     = fullName.split(' ');
const firstName = esc(parts.length > 1 ? parts.slice(0, -1).join(' ') : fullName);
const lastName  = esc(parts.length > 1 ? parts[parts.length - 1] : '');

const contactTokens = contactRaw
  .replace(/\n/g, ' | ')
  .split('|')
  .map(s => s.trim())
  .filter(Boolean);

const email      = esc(contactTokens.find(p => p.includes('@')) ?? '');
const phone      = esc(contactTokens.find(p => /\d{3}[-.\s]\d{3}/.test(p)) ?? '');
const linkedinRaw = contactTokens.find(p => /linkedin/i.test(p)) ?? '';
const linkedin   = esc(linkedinRaw.replace(/^https?:\/\//i, '').replace(/^www\./i, '').replace(/^linkedin\.com\/in\//i, '').replace(/\/+$/, ''));
const city = esc(contactTokens.find(p => !p.includes('@') && !/\d{3}[-.\s]\d{3}/.test(p) && !/linkedin/i.test(p)) ?? '');

const summaryText = esc(summaryRaw.replace(/\n/g, ' ').trim());

function buildExperience(text) {
  if (!text) return '\\cvitem{}{}';
  const lines = text.split('\n');
  const blocks = [];
  let current = [];
  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed) continue;
    if (trimmed.includes('|') && !trimmed.startsWith('-') && current.length > 0) {
      blocks.push(current);
      current = [];
    }
    current.push(trimmed);
  }
  if (current.length) blocks.push(current);
  let out = '';
  for (const block of blocks) {
    const [co, loc]    = (block[0] || '').split('|').map(s => s.trim());
    const [title, dates] = (block[1] || '').split('|').map(s => s.trim());
    const bullets = block.slice(2).filter(l => l.startsWith('- '));
    out += `\n\\cventry{${esc(dates)}}{${esc(title)}}{${esc(co)}}{${esc(loc)}}{}{
`;
    if (bullets.length) {
      out += '  \\begin{itemize}\n';
      for (const b of bullets) {
        out += `    \\item ${esc(b.replace(/^-\s+/, ''))}\n`;
      }
      out += '  \\end{itemize}\n';
    }
    out += '}\n';
  }
  return out || '\\cvitem{}{}';
}

function buildEducation(text) {
  if (!text) return '\\cvitem{}{}';
  const lines = text.split('\n').map(l => l.trim()).filter(l => l && !l.startsWith('-'));
  let out = '';
  for (let i = 0; i + 1 < lines.length; i += 2) {
    const [school, loc]   = lines[i].split('|').map(s => s.trim());
    const [degree, dates] = lines[i+1].split('|').map(s => s.trim());
    out += `\\cventry{${esc(dates)}}{${esc(degree)}}{${esc(school)}}{${esc(loc)}}{}{}\n`;
  }
  return out || '\\cvitem{}{}';
}

function buildSkills(text) {
  if (!text) return '\\cvitem{}{}';
  return text.split('\n').map(l => l.trim()).filter(Boolean).map(line => {
    const clean = line.replace(/^-\s*/, '');
    const ci    = clean.indexOf(':');
    if (ci > 0) return `\\cvitem{${esc(clean.slice(0, ci).trim())}}{${esc(clean.slice(ci + 1).trim())}}`;
    return `\\cvitem{}{${esc(clean)}}`;
  }).join('\n');
}

const latex = `\\documentclass[11pt,a4paper,sans]{moderncv}
\\moderncvstyle{banking}
\\moderncvcolor{blue}
\\usepackage[scale=0.88]{geometry}
\\usepackage{fontspec}
\\usepackage{hyperref}
\\nopagenumbers{}

\\name{${firstName}}{${lastName}}
\\phone[mobile]{${phone}}
\\email{${email}}
\\social[linkedin]{${linkedin}}
\\address{${city}}{}{}

\\begin{document}
\\makecvtitle

\\section{Summary}
\\cvitem{}{${summaryText}}

\\section{Professional Experience}
${buildExperience(experienceRaw)}
\\section{Education}
${buildEducation(educationRaw)}

\\section{Skills}
${buildSkills(skillsRaw)}

\\end{document}
`;

return {
  json: {
    latex,
    output:         $json.output,
    company:        $json.company        ?? '',
    title:          $json.title          ?? '',
    jobLink:        $json.jobLink        ?? '',
    postedAt:       $json.postedAt       ?? '',
    location:       $json.location       ?? '',
    employmentType: $json.employmentType ?? '',
    seniorityLevel: $json.seniorityLevel ?? '',
    jobDescription: $json.jobDescription ?? ''
  }
};

const src = $('Build LaTeX Resume').item.json;
const company        = src.company        ?? '';
const title          = src.title          ?? '';
const postedAt       = src.postedAt       ?? new Date().toISOString().slice(0, 10);
const jobLink        = src.jobLink        ?? '';
const location       = src.location       ?? '';
const employmentType = src.employmentType ?? '';
const seniorityLevel = src.seniorityLevel ?? '';
const jobDescription = src.jobDescription ?? '';
const output         = src.output         ?? '';
const safeTitle   = title.replace(/[\/\\:*?"<>|]/g, '').slice(0, 80);
const safeCompany = company.replace(/[\/\\:*?"<>|]/g, '').slice(0, 60);
const docTitle    = `${safeTitle} - ${postedAt}`;
return {
  json: { output, docTitle, company, title, roleName: safeTitle, postedAt, jobLink, location, employmentType, seniorityLevel, jobDescription },
  binary: { data: $input.item.binary.pdfData }
};

const items = $input.all();
const esc = s => String(s ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const today = new Date().toISOString().slice(0, 10);
const jobItems = $('Limit to 5 Jobs').all();
const uploadItems = $('Upload PDF to Drive').all();
const processedItems = jobItems.map((jobItem, index) => {
  const uploadData = uploadItems[index]?.json ?? {};
  const pdfId = uploadData.id ?? '';
  const pdfLink = pdfId ? `https://drive.google.com/file/d/${pdfId}/view` : '';
  return { company: jobItem.json.company ?? '', roleName: jobItem.json.title ?? '', postedAt: jobItem.json.postedAt ?? '', jobLink: jobItem.json.jobLink ?? '', pdfLink };
});
let body = `<div style="font-family:Arial,sans-serif;font-size:14px;line-height:1.5;color:#222;"><h2>Your ATS resumes are ready (${processedItems.length})</h2><p>Generated: ${new Date().toLocaleString()}</p><table style="border-collapse:collapse;width:100%;"><thead><tr><th style="text-align:left;padding:10px;border-bottom:2px solid #ddd;">Company</th><th style="text-align:left;padding:10px;border-bottom:2px solid #ddd;">Role</th><th style="text-align:left;padding:10px;border-bottom:2px solid #ddd;">Posted</th><th style="text-align:left;padding:10px;border-bottom:2px solid #ddd;">Job</th><th style="text-align:left;padding:10px;border-bottom:2px solid #ddd;">Resume</th></tr></thead><tbody>`;
for (const it of processedItems) {
  body += `<tr><td style="padding:10px;border-bottom:1px solid #eee;font-weight:700;">${esc(it.company)}</td><td style="padding:10px;border-bottom:1px solid #eee;">${esc(it.roleName)}</td><td style="padding:10px;border-bottom:1px solid #eee;">${esc(it.postedAt)}</td><td style="padding:10px;border-bottom:1px solid #eee;"><a href="${it.jobLink}">🔗 View Job</a></td><td style="padding:10px;border-bottom:1px solid #eee;"><a href="${it.pdfLink}">📄 PDF Resume</a></td></tr>`;
}
body += `</tbody></table><p style="color:#aaa;font-size:11px;margin-top:16px;">ATS Resume Agent — ${today}</p></div>`;
return [{ json: { subject: `ATS Resumes Ready (${processedItems.length}) — ${today}`, body } }];

const allJobs = $('Limit to 5 Jobs').all();
const config = $('Workflow Configuration1').first().json;
const supabaseUrl = config.supabaseUrl;
const supabaseKey = config.supabaseKey;
const existingUrls = new Set();
async function checkJobExists(jobUrl) {
  try {
    const response = await fetch(`${supabaseUrl}/rest/v1/jobs?job_url=eq.${encodeURIComponent(jobUrl)}&select=job_url`, { method: 'GET', headers: { 'apikey': supabaseKey, 'Authorization': `Bearer ${supabaseKey}`, 'Content-Type': 'application/json' } });
    if (!response.ok) return null;
    const data = await response.json();
    return data.length > 0 ? jobUrl : null;
  } catch (error) { return null; }
}
const checkPromises = allJobs.map(job => checkJobExists(job.json.jobLink));
const results = await Promise.all(checkPromises);
for (const url of results) { if (url) existingUrls.add(url); }
const newJobs = allJobs.filter(job => !existingUrls.has(job.json.jobLink));
return newJobs;

const agentOutput = $json.output ?? '';
const jobData = $('Prepare Job Query').item.json;
return { json: { output: agentOutput, title: jobData.title ?? '', company: jobData.company ?? '', jobLink: jobData.jobLink ?? '', postedAt: jobData.postedAt ?? '', location: jobData.location ?? '', employmentType: jobData.employmentType ?? '', seniorityLevel: jobData.seniorityLevel ?? '', jobDescription: jobData.jobDescription ?? '' } };
